// --- ENTRADAS ---
// O novo resumo que vem do Gemini (Resumidor)
const newUpdatedSummary = $json.resumo;//JSON.stringify($json.resumo).replace(/'/g, "''"); 
// O histórico recente que mantemos
const recentHistory = $json.historico_otimizado;// JSON.stringify($json.historico_otimizado).replace(/'/g, "`");
var contextoMemoria = $('Validate Inputs').item.json.pessoa.contexto_memoria;

contextoMemoria.resumo_historico = newUpdatedSummary;
contextoMemoria.conversas_recentes = recentHistory;

const novoHistorico = JSON.stringify(contextoMemoria);



// Retorna a query pronta para ser executada
$input.item.json = {contextoMemoria, novoHistorico}
return $input.item;

const history = ($json.pessoa.contexto_memoria.conversas_recentes === null)? [] : ($json.pessoa.contexto_memoria.conversas_recentes || []);
// Conta o número de vezes que "Usuário:" ou "Agente:" aparece e divide por 2 para ter o número de interações.
const messageCount = history.length;

const limiteDeMensagens = 50;

return {
  json: {
    message_count: messageCount,
    limiteDeMensagens
  }
};

// 1. Captura o histórico (que pode vir como String única ou Array de objetos/strings)
let fullHistory = $('Validate Inputs').first().json.pessoa.contexto_memoria.conversas_recentes || [];

// 2. Normalização: Garante que seja um Array de mensagens
let messages = fullHistory;

// 4. A Lógica da "Metade" (Split 50/50)
const splitIndex = Math.floor(messages.length / 2);

const oldPart = messages.slice(0, splitIndex); // A metade antiga
const newPart = messages.slice(splitIndex);    // A metade recente

// 5. Saída
return {
    json: {
        run_summary: true,
        text_to_summarize: oldPart, // Isso vai para a LLM resumir
        recent_context: newPart     // Isso passa direto
    }
};

function isNotEmptyObject(obj) {
  // Ensure the input is actually an object and not null
  if (typeof obj !== 'object' || obj === null) {
    return false; // Or throw an error, depending on desired behavior
  }
  return Object.keys(obj).length > 0;
}
/**
 * Verifica se a string fornecida não é nula, indefinida, vazia ("") ou
 * composta apenas por espaços em branco.
 *
 * @param {string | null | undefined} str A string a ser verificada.
 * @returns {boolean} Retorna true se a string tiver conteúdo significativo, caso contrário, false.
 */
function isStringNotEmpty(str) {
  // 1. Verifica se a string é nula ou indefinida (ou de outro tipo de dado não string).
  if (typeof str !== 'string' || str === null || str === undefined) {
    return false;
  }

  // 2. Usa o método .trim() para remover espaços em branco do início e fim
  //    e verifica se o comprimento restante é maior que zero.
  return str.trim().length > 0;
}

if (!isNotEmptyObject($json.pessoa)) throw new Error('Objeto Pessoa inválido');
if (!isNotEmptyObject($json.loja)) throw new Error('Objeto Loja inválido');
if (!isNotEmptyObject($json.prompt)) throw new Error('Objeto Prompt inválido');

return $input.item;

// Loop over input items and add a new field called 'myNewField' to the JSON of each one
for (const item of $input.all()) {
  if (item.json.error) 
  item.json.errorMessage = 'error ao processar o nó resumidor';
}

return $input.all();

const input = $('Validate Inputs').first().json;

input.pessoa = $json;

$input.item.json = input;

return $input.item;

const summary = $json.text || ""; // O Resumo da metade velha
const recent = $('Function-Dividir-Historico').item.json.recent_context; // A metade nova crua

// Se não houve resumo (conversa curta), o summary estará vazio, o que é correto.

let historyFinal = [];
let msgResumo = {};

if (summary){
  msgResumo = {
    createdAt: DateTime.now(),
    agente: summary
  }
  historyFinal.push(msgResumo);
  historyFinal = historyFinal.concat(...recent);
} else {
  historyFinal = recent;
}



return {
    json: {
        resumo: msgResumo,
        historico_otimizado: historyFinal
    }
}
